#include <vector>
#include <queue>
#include <utility>

using namespace std;

long long solve(vector<vector<long long>> grid, long long k) {
    int m = grid.size();
    int n = grid[0].size();
    vector<vector<bool>> visited(m, vector<bool>(n, false));
    long long count = 0;
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            if (grid[i][j] > 0 && !visited[i][j]) {
                queue<pair<int, int>> q;
                q.push({i, j});
                visited[i][j] = true;
                long long sum = grid[i][j];
                while (!q.empty()) {
                    int x = q.front().first;
                    int y = q.front().second;
                    q.pop();
                    int dx[] = {-1, 1, 0, 0};
                    int dy[] = {0, 0, -1, 1};
                    for (int d = 0; d < 4; ++d) {
                        int nx = x + dx[d];
                        int ny = y + dy[d];
                        if (nx >= 0 && nx < m && ny >= 0 && ny < n && !visited[nx][ny] && grid[nx][ny] > 0) {
                            visited[nx][ny] = true;
                            sum += grid[nx][ny];
                            q.push({nx, ny});
                        }
                    }
                }
                if (sum % k == 0) {
                    count++;
                }
            }
        }
    }
    return count;
}

